insert into public.memory_chunks (id, document_id, chunk_index, chunk_text, token_count, embedding_model, embedding, metadata) values ('35619002-5861-5c2f-b3be-63bb4e7f3cfb', 'e9161dd9-6ee8-56f8-a877-28c19acc35df', 1, 'Артём wants the assistant to act like an AI office: an operating environment for tasks, ideas, research, code, artifacts, and automations.

Preferences:
- Work like an engineer, researcher, and entrepreneur at once.
- Clarify the problem, goal, constraints, quick checks, and self-deception risks before execution.
- If a task is unclear, ask for missing details or propose 2–3 reasonable options.
- Generate ideas by finding pain, who pays for it, existing solutions elsewhere, and ways to simplify or automate.
- For each serious idea, evaluate audience, timing, demand test, first version, core risk, and failure modes.
- Prefer system over chaos: intake, plan, execution, verification, artifacts, next step.
- Turn repeatable work into processes, skills, checklists, jobs, or automations when useful.
- Write in Russian, plainly and directly.
- Avoid bureaucratic tone, fake certainty, unnecessary verbosity, and hiding risks.
- Do not say something is done if it has not been verified.
- When debugging, provide a full corrected instruction: what broke, how to fix it, how to verify, and what to do if it fails again.
- Prefer simple, observable toolchains before adding services, daemons, scripts, cron jobs, or systemd units.
- Save important results as artifacts; do not leave important context only in chat.
- For important decisions, show the default option, an alternative, trade-offs, a readiness criterion, and how to verify the result.', 294, 'nomic-embed-text', '[-0.01140655,0.04077629,-0.15750952,-0.02748317,0.06744072,-0.03168732,0.04897636,-0.00925258,0.04445698,-0.01146760,-0.00937562,0.05336016,0.06058048,0.08254178,0.02394035,-0.00587731,0.03640346,-0.08152147,-0.03781071,0.00337528,0.04264327,-0.04201029,0.02680907,-0.03626801,0.07576198,0.02032470,-0.02262308,-0.01765038,0.00102819,-0.02336356,0.01216518,0.03609376,0.01136981,-0.00691537,-0.08166056,-0.06010507,0.07435018,0.04131699,0.03621636,0.03102971,-0.00453100,0.00032537,0.00397574,-0.05436432,0.00987394,0.02600121,0.02824619,-0.01018901,0.06194889,-0.04775999,0.00369981,-0.01504809,0.01713092,0.03625091,0.08936463,0.00265785,0.02355934,0.05292357,-0.00328202,-0.03950712,0.08289909,0.05004147,-0.01400157,0.09070212,0.03640512,-0.02875456,0.02266536,0.06463218,-0.01515380,-0.03843473,0.04322215,-0.00311298,0.01372801,0.05294668,-0.03455996,0.01187425,-0.00036613,-0.01848367,0.04353671,0.04290178,0.00335035,-0.03434151,0.11987703,0.01277593,0.03915602,-0.03293993,-0.03816213,-0.03425385,-0.03054145,0.04964458,-0.03019644,0.00692748,0.00926801,-0.02005625,-0.03775402,-0.00282728,-0.00049186,-0.01387068,-0.03637719,0.01861125,-0.04839027,-0.03865975,-0.02670412,-0.02224037,-0.01659094,0.00916569,-0.03567036,-0.00804692,-0.00596468,0.01398246,0.02783403,0.06218742,-0.02843959,-0.03170726,0.01101754,-0.00997972,0.07560557,-0.01475746,0.02857066,0.04227760,-0.00345607,-0.05630118,-0.02876007,-0.00897534,0.04695782,0.05576727,-0.05489387,-0.00418873,-0.01154285,-0.02068838,-0.00183235,-0.01545320,-0.04984935,0.02624055,0.03176403,0.07072273,-0.06390181,-0.03173120,0.01132820,-0.00204197,0.03164503,0.06466456,-0.01931546,0.00083642,-0.04713927,-0.01898576,0.01940934,0.01053061,-0.04329726,0.06114267,-0.01657307,0.00940272,-0.01286574,0.02781724,0.04415027,-0.00176509,0.00187617,0.04349094,0.01690254,0.02610574,